  1→import type { EvaluationResult } from '@agentv/core';
  2→
  3→export interface HistogramBin {
  4→  readonly range: readonly [number, number];
  5→  count: number;
  6→}
  7→
  8→export interface EvaluationSummary {
  9→  readonly total: number;
 10→  readonly mean: number;
 11→  readonly median: number;
 12→  readonly min: number;
 13→  readonly max: number;
 14→  readonly standardDeviation?: number;
 15→  readonly histogram: readonly HistogramBin[];
 16→  readonly topResults: readonly EvaluationResult[];
 17→  readonly bottomResults: readonly EvaluationResult[];
 18→  readonly errorCount: number;
 19→  readonly errors: readonly { readonly testId: string; readonly error: string }[];
 20→  readonly executionErrorCount: number;
 21→  readonly qualityFailureCount: number;
 22→  readonly passedCount: number;
 23→  readonly byFailureStage: Readonly<Record<string, number>>;
 24→  readonly byFailureReason: Readonly<Record<string, number>>;
 25→}
 26→
 27→const HISTOGRAM_BREAKPOINTS = [0, 0.2, 0.4, 0.6, 0.8, 1];
 28→
 29→function computeMean(values: readonly number[]): number {
 30→  if (values.length === 0) {
 31→    return 0;
 32→  }
 33→  const sum = values.reduce((acc, value) => acc + value, 0);
 34→  return sum / values.length;
 35→}
 36→
 37→function computeMedian(values: readonly number[]): number {
 38→  if (values.length === 0) {
 39→    return 0;
 40→  }
 41→  const sorted = [...values].sort((a, b) => a - b);
 42→  const mid = Math.floor(sorted.length / 2);
 43→  if (sorted.length % 2 === 0) {
 44→    return (sorted[mid - 1] + sorted[mid]) / 2;
 45→  }
 46→  return sorted[mid];
 47→}
 48→
 49→function computeStandardDeviation(values: readonly number[]): number | undefined {
 50→  if (values.length < 2) {
 51→    return undefined;
 52→  }
 53→  const mean = computeMean(values);
 54→  const variance =
 55→    values.reduce((acc, value) => acc + (value - mean) ** 2, 0) / (values.length - 1);
 56→  return Math.sqrt(variance);
 57→}
 58→
 59→function buildHistogram(values: readonly number[]): readonly HistogramBin[] {
 60→  const bins: HistogramBin[] = [];
 61→  for (let index = 0; index < HISTOGRAM_BREAKPOINTS.length - 1; index += 1) {
 62→    bins.push({
 63→      range: [HISTOGRAM_BREAKPOINTS[index], HISTOGRAM_BREAKPOINTS[index + 1]] as const,
 64→      count: 0,
 65→    });
 66→  }
 67→
 68→  for (const value of values) {
 69→    for (const bin of bins) {
 70→      const [start, end] = bin.range;
 71→      const isLastBin = end === HISTOGRAM_BREAKPOINTS[HISTOGRAM_BREAKPOINTS.length - 1];
 72→      const withinRange = isLastBin
 73→        ? value >= start && value <= end
 74→        : value >= start && value < end + 1e-9;
 75→      if (withinRange) {
 76→        bin.count += 1;
 77→        break;
 78→      }
 79→    }
 80→  }
 81→
 82→  return bins;
 83→}
 84→
 85→export function calculateEvaluationSummary(
 86→  results: readonly EvaluationResult[],
 87→): EvaluationSummary {
 88→  const total = results.length;
 89→
 90→  // Track errors
 91→  const errors = results
 92→    .filter((result) => result.error !== undefined)
 93→    .map((result) => ({ testId: result.testId, error: result.error as string }));
 94→  const errorCount = errors.length;
 95→
 96→  if (total === 0) {
 97→    return {
 98→      total: 0,
 99→      mean: 0,
100→      median: 0,
101→      min: 0,
102→      max: 0,
103→      standardDeviation: undefined,
104→      histogram: buildHistogram([]),
105→      topResults: [],
106→      bottomResults: [],
107→      errorCount: 0,
108→      errors: [],
109→      executionErrorCount: 0,
110→      qualityFailureCount: 0,
111→      passedCount: 0,
112→      byFailureStage: {},
113→      byFailureReason: {},
114→    };
115→  }
116→
117→  // Separate execution errors from quality results
118→  const executionErrors = results.filter((r) => r.executionStatus === 'execution_error');
119→  const qualityResults = results.filter((r) => r.executionStatus !== 'execution_error');
120→  const qualityScores = qualityResults.map((r) => r.score);
121→
122→  // Compute quality metrics from non-execution-error results only
123→  const mean = computeMean(qualityScores);
124→  const median = computeMedian(qualityScores);
125→  const min = qualityScores.length > 0 ? Math.min(...qualityScores) : 0;
126→  const max = qualityScores.length > 0 ? Math.max(...qualityScores) : 0;
127→  const standardDeviation = computeStandardDeviation(qualityScores);
128→  const histogram = buildHistogram(qualityScores);
129→
130→  // Top/bottom results consider only non-execution-error results
131→  const sortedResults = [...qualityResults].sort((a, b) => b.score - a.score);
132→  const topResults = sortedResults.slice(0, Math.min(3, sortedResults.length));
133→  const bottomResults = sortedResults.slice(-Math.min(3, sortedResults.length));
134→
135→  // Count by execution status
136→  const executionErrorCount = executionErrors.length;
137→  const qualityFailureCount = results.filter((r) => r.executionStatus === 'quality_failure').length;
138→  const passedCount = results.filter((r) => r.executionStatus === 'ok').length;
139→
140→  // Aggregate by failure stage and reason (execution errors only)
141→  const byFailureStage: Record<string, number> = {};
142→  const byFailureReason: Record<string, number> = {};
143→  for (const result of executionErrors) {
144→    if (result.failureStage) {
145→      byFailureStage[result.failureStage] = (byFailureStage[result.failureStage] ?? 0) + 1;
146→    }
147→    if (result.failureReasonCode) {
148→      byFailureReason[result.failureReasonCode] =
149→        (byFailureReason[result.failureReasonCode] ?? 0) + 1;
150→    }
151→  }
152→
153→  return {
154→    total,
155→    mean,
156→    median,
157→    min,
158→    max,
159→    standardDeviation,
160→    histogram,
161→    topResults,
162→    bottomResults,
163→    errorCount,
164→    errors,
165→    executionErrorCount,
166→    qualityFailureCount,
167→    passedCount,
168→    byFailureStage,
169→    byFailureReason,
170→  };
171→}
172→
173→function formatScore(value: number): string {
174→  return value.toFixed(3);
175→}
176→
177→export function formatEvaluationSummary(summary: EvaluationSummary): string {
178→  if (summary.total === 0) {
179→    return '\nNo results to summarize';
180→  }
181→
182→  const lines: string[] = [];
183→
184→  // Display errors first if any exist
185→  if (summary.errorCount > 0) {
186→    lines.push('\n==================================================');
187→    lines.push('EXECUTION ERRORS');
188→    lines.push('==================================================');
189→    for (const error of summary.errors) {
190→      lines.push(`\n❌ ${error.testId}`);
191→      lines.push(`   ${error.error}`);
192→    }
193→    lines.push('');
194→  }
195→
196→  // Overall verdict line
197→  const overallPassed =
198→    summary.passedCount === summary.total - summary.executionErrorCount ||
199→    (summary.qualityFailureCount === 0 && summary.executionErrorCount === 0);
200→  const overallVerdict = overallPassed ? 'PASS' : 'FAIL';
201→  const useColor = !(process.env.NO_COLOR !== undefined) && (process.stdout.isTTY ?? false);
202→  const verdictColor = overallPassed ? '\x1b[32m' : '\x1b[31m';
203→  const verdictText = `RESULT: ${overallVerdict}  (${summary.passedCount}/${summary.total} passed, mean score: ${formatScore(summary.mean)})`;
204→
205→  lines.push('\n==================================================');
206→  if (useColor) {
207→    lines.push(`\x1b[1m${verdictColor}${verdictText}\x1b[0m`);
208→  } else {
209→    lines.push(verdictText);
210→  }
211→  lines.push('==================================================');
212→
213→  lines.push('');
214→  lines.push('EVALUATION SUMMARY');
215→  lines.push('==================================================');
216→  lines.push(`Total tests: ${summary.total}`);
217→  lines.push(`Passed: ${summary.passedCount}`);
218→  if (summary.qualityFailureCount > 0) {
219→    lines.push(`Quality failures: ${summary.qualityFailureCount}`);
220→  }
221→  if (summary.executionErrorCount > 0) {
222→    lines.push(`Execution errors: ${summary.executionErrorCount}`);
223→  }
224→
225→  if (summary.executionErrorCount > 0) {
226→    const qualityCount = summary.total - summary.executionErrorCount;
227→    lines.push(
228→      `Mean score: ${formatScore(summary.mean)} (${qualityCount} quality tests, ${summary.executionErrorCount} execution errors excluded)`,
229→    );
230→  } else {
231→    lines.push(`Mean score: ${formatScore(summary.mean)}`);
232→  }
233→  lines.push(`Median score: ${formatScore(summary.median)}`);
234→  lines.push(`Min score: ${formatScore(summary.min)}`);
235→  lines.push(`Max score: ${formatScore(summary.max)}`);
236→  if (typeof summary.standardDeviation === 'number') {
237→    lines.push(`Std deviation: ${formatScore(summary.standardDeviation)}`);
238→  }
239→
240→  lines.push('\nScore distribution:');
241→  for (const bin of summary.histogram) {
242→    const [start, end] = bin.range;
243→    lines.push(`  ${start.toFixed(1)}-${end.toFixed(1)}: ${bin.count}`);
244→  }
245→
246→  lines.push('\nTop performing tests:');
247→  summary.topResults.forEach((result, index) => {
248→    lines.push(`  ${index + 1}. ${result.testId}: ${formatScore(result.score)}`);
249→  });
250→
251→  lines.push('\nLowest performing tests:');
252→  summary.bottomResults.forEach((result, index) => {
253→    lines.push(`  ${index + 1}. ${result.testId}: ${formatScore(result.score)}`);
254→  });
255→
256→  const failureStageEntries = Object.entries(summary.byFailureStage);
257→  if (failureStageEntries.length > 0) {
258→    lines.push('\nExecution errors by stage:');
259→    for (const [stage, count] of failureStageEntries) {
260→      lines.push(`  ${stage}: ${count}`);
261→    }
262→  }
263→
264→  const failureReasonEntries = Object.entries(summary.byFailureReason);
265→  if (failureReasonEntries.length > 0) {
266→    lines.push('\nExecution errors by reason:');
267→    for (const [reason, count] of failureReasonEntries) {
268→      lines.push(`  ${reason}: ${count}`);
269→    }
270→  }
271→
272→  return lines.join('\n');
273→}
274→
275→/**
276→ * Format a matrix summary table showing tests × targets.
277→ */
278→export function formatMatrixSummary(results: readonly EvaluationResult[]): string {
279→  // Collect unique targets and test IDs
280→  const targetSet = new Set<string>();
281→  const testIdSet = new Set<string>();
282→  for (const result of results) {
283→    targetSet.add(result.target);
284→    testIdSet.add(result.testId);
285→  }
286→
287→  const targets = [...targetSet].sort();
288→  const testIds = [...testIdSet].sort();
289→
290→  if (targets.length < 2) {
291→    return '';
292→  }
293→
294→  // Build lookup: testId -> target -> score
295→  const scoreMap = new Map<string, Map<string, number>>();
296→  for (const result of results) {
297→    if (!scoreMap.has(result.testId)) {
298→      scoreMap.set(result.testId, new Map());
299→    }
300→    scoreMap.get(result.testId)?.set(result.target, result.score);
301→  }
302→
303→  const lines: string[] = [];
304→  lines.push('\n==================================================');
305→  lines.push('MATRIX RESULTS (tests × targets)');
306→  lines.push('==================================================');
307→
308→  // Header row
309→  const testIdColWidth = Math.max(7, ...testIds.map((id) => id.length));
310→  const targetColWidth = Math.max(7, ...targets.map((t) => t.length));
311→  const header = `${'Test'.padEnd(testIdColWidth)}  ${targets.map((t) => t.padEnd(targetColWidth)).join('  ')}`;
312→  lines.push(header);
313→  lines.push('-'.repeat(header.length));
314→
315→  // Data rows
316→  for (const testId of testIds) {
317→    const cells = targets.map((target) => {
318→      const score = scoreMap.get(testId)?.get(target);
319→      return score !== undefined
320→        ? formatScore(score).padEnd(targetColWidth)
321→        : '-'.padEnd(targetColWidth);
322→    });
323→    lines.push(`${testId.padEnd(testIdColWidth)}  ${cells.join('  ')}`);
324→  }
325→
326→  // Per-target averages
327→  lines.push('-'.repeat(header.length));
328→  const avgCells = targets.map((target) => {
329→    const scores = results.filter((r) => r.target === target).map((r) => r.score);
330→    const avg = scores.length > 0 ? scores.reduce((a, b) => a + b, 0) / scores.length : 0;
331→    return formatScore(avg).padEnd(targetColWidth);
332→  });
333→  lines.push(`${'Average'.padEnd(testIdColWidth)}  ${avgCells.join('  ')}`);
334→
335→  return lines.join('\n');
336→}
