 93→}
 94→
 95→function normalizeString(value: unknown): string | undefined {
 96→  if (typeof value !== 'string') {
 97→    return undefined;
 98→  }
 99→  const trimmed = value.trim();
100→  return trimmed.length > 0 ? trimmed : undefined;
