103→export function resolveTimestampPlaceholder(value: string): string {
104→  if (!value.includes('{timestamp}')) {
105→    return value;
106→  }
107→  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
108→  return value.replaceAll('{timestamp}', timestamp);
109→}
