 48→const EVAL_SUBCOMMANDS = new Set(['run', 'prompt', 'assert']);
 49→
 50→/**
 51→ * Top-level CLI command names (excluding `eval` itself).
 52→ * Used to distinguish `agentv eval …` from `agentv prompt eval …`.
 53→ */
 54→const TOP_LEVEL_COMMANDS = new Set([
 55→  'prompt',
 56→  'compare',
 57→  'convert',
 58→  'create',
 59→  'init',
 60→  'pipeline',
 61→  'results',
