 71→/**
 72→ * Preprocess argv for convenience aliases:
 73→ * - `--eval-id` → `--test-id`
 74→ * - `agentv eval <non-subcommand>` → `agentv eval run <non-subcommand>`
 75→ *   (backward compat: `eval` used to be a direct command, now it's a group)
 76→ */
 77→export function preprocessArgv(argv: string[]): string[] {
 78→  const result = [...argv];
 79→
 80→  // Rewrite --eval-id → --test-id (convenience alias)
 81→  for (let i = 0; i < result.length; i++) {
 82→    if (result[i] === '--eval-id') {
 83→      result[i] = '--test-id';
 84→    } else if (result[i].startsWith('--eval-id=')) {
 85→      result[i] = `--test-id=${result[i].slice('--eval-id='.length)}`;
 86→    }
 87→  }
 88→
 89→  // Implicit `run` subcommand: `agentv eval <arg>` → `agentv eval run <arg>`
 90→  // when the first arg after `eval` is not a known eval subcommand.
 91→  // This preserves backward compatibility now that `eval` is a subcommands group.
 92→  // Only applies when `eval` is the top-level subcommand, NOT when it appears
 93→  // inside another command (e.g. `agentv prompt eval …`).
 94→  // Exception: `--help` / `-h` should show the eval group help, not run's help.
 95→  const evalIdx = result.indexOf('eval');
 96→  if (evalIdx !== -1) {
 97→    // Ensure no top-level command appears before `eval` in the argv —
 98→    // if one does, `eval` is a nested subcommand (e.g. `prompt eval`).
 99→    const isTopLevel = !result.slice(0, evalIdx).some((arg) => TOP_LEVEL_COMMANDS.has(arg));
100→    if (isTopLevel) {
101→      const nextArg = result[evalIdx + 1];
102→      if (
103→        nextArg !== undefined &&
104→        !EVAL_SUBCOMMANDS.has(nextArg) &&
105→        nextArg !== '--help' &&
106→        nextArg !== '-h'
107→      ) {
108→        result.splice(evalIdx + 1, 0, 'run');
109→      }
110→    }
111→  }
112→
113→  return result;
114→}
