116→export async function runCli(argv: string[] = process.argv): Promise<void> {
117→  // Kick off update check: reads from local cache (fast), spawns a detached
118→  // child to refresh if stale. The notice is printed on process exit so it
119→  // appears after command output, even if the command calls process.exit().
120→  let updateNotice: string | null = null;
121→  process.on('exit', () => {
122→    if (updateNotice) process.stderr.write(`\n${updateNotice}\n`);
123→  });
124→  getUpdateNotice(packageJson.version).then((n) => {
125→    updateNotice = n;
126→  });
127→
128→  const processedArgv = preprocessArgv(argv);
129→  await run(binary(app), processedArgv);
130→}
