 6→export function escapeXml(str: string): string {
 7→  return str
 8→    .replace(/&/g, '&amp;')
 9→    .replace(/</g, '&lt;')
10→    .replace(/>/g, '&gt;')
11→    .replace(/"/g, '&quot;')
12→    .replace(/'/g, '&apos;');
13→}
