15→export class JunitWriter {
16→  private readonly filePath: string;
17→  private readonly results: EvaluationResult[] = [];
18→  private closed = false;
19→
20→  private constructor(filePath: string) {
21→    this.filePath = filePath;
22→  }
23→
24→  static async open(filePath: string): Promise<JunitWriter> {
25→    await mkdir(path.dirname(filePath), { recursive: true });
26→    return new JunitWriter(filePath);
27→  }
28→
29→  async append(result: EvaluationResult): Promise<void> {
30→    if (this.closed) {
31→      throw new Error('Cannot write to closed JUnit writer');
32→    }
33→    this.results.push(result);
34→  }
35→
36→  async close(): Promise<void> {
37→    if (this.closed) {
38→      return;
39→    }
40→    this.closed = true;
41→
42→    const grouped = new Map<string, EvaluationResult[]>();
43→    for (const result of this.results) {
44→      const suite = result.eval_set ?? 'default';
45→      const existing = grouped.get(suite);
46→      if (existing) {
47→        existing.push(result);
48→      } else {
49→        grouped.set(suite, [result]);
50→      }
51→    }
52→
53→    const suiteXmls: string[] = [];
54→    for (const [suiteName, results] of grouped) {
55→      const failures = results.filter((r) => r.score < 0.5).length;
56→      const errors = results.filter((r) => r.error !== undefined).length;
57→
58→      const testCases = results.map((r) => {
59→        const time = r.durationMs ? (r.durationMs / 1000).toFixed(3) : '0.000';
60→
61→        let inner = '';
62→        if (r.error) {
63→          inner = `\n      <error message="${escapeXml(r.error)}">${escapeXml(r.error)}</error>\n    `;
64→        } else if (r.score < 0.5) {
65→          const message = `score=${r.score.toFixed(3)}`;
66→          const failedAssertions = r.assertions.filter((a) => !a.passed);
67→          const detail = [
68→            `Score: ${r.score.toFixed(3)}`,
69→            failedAssertions.length > 0
70→              ? `Failed: ${failedAssertions.map((a) => a.text).join(', ')}`
71→              : '',
72→          ]
73→            .filter(Boolean)
74→            .join('\n');
75→          inner = `\n      <failure message="${escapeXml(message)}">${escapeXml(detail)}</failure>\n    `;
76→        }
77→
78→        return `    <testcase name="${escapeXml(r.testId)}" classname="${escapeXml(suiteName)}" time="${time}">${inner}</testcase>`;
79→      });
80→
81→      suiteXmls.push(
82→        `  <testsuite name="${escapeXml(suiteName)}" tests="${results.length}" failures="${failures}" errors="${errors}">\n${testCases.join('\n')}\n  </testsuite>`,
83→      );
84→    }
85→
86→    const totalTests = this.results.length;
87→    const totalFailures = this.results.filter((r) => r.score < 0.5).length;
88→    const totalErrors = this.results.filter((r) => r.error !== undefined).length;
89→
90→    const xml = `<?xml version="1.0" encoding="UTF-8"?>\n<testsuites tests="${totalTests}" failures="${totalFailures}" errors="${totalErrors}">\n${suiteXmls.join('\n')}\n</testsuites>\n`;
91→
92→    await writeFile(this.filePath, xml, 'utf8');
93→  }
94→}
