 10→/**
 11→ * JSON primitive values appearing in AgentV payloads.
 12→ */
 13→export type JsonPrimitive = string | number | boolean | null;
 14→
 15→/**
 16→ * Immutable JSON object representation for test fixtures.
 17→ */
 18→export interface JsonObject {
 19→  readonly [key: string]: JsonValue;
 20→}
 21→
 22→/**
 23→ * Recursive JSON value supporting nested structures.
 24→ */
 25→export type JsonValue = JsonPrimitive | JsonObject | readonly JsonValue[];
 26→
 27→const TEST_MESSAGE_ROLE_VALUES = ['system', 'user', 'assistant', 'tool'] as const;
 28→
 29→/**
 30→ * Immutable list of supported message roles.
 31→ */
 32→export const TEST_MESSAGE_ROLES = TEST_MESSAGE_ROLE_VALUES;
 33→
 34→/**
 35→ * Role literals used by test messages.
 36→ */
 37→export type TestMessageRole = (typeof TEST_MESSAGE_ROLE_VALUES)[number];
 38→
 39→const TEST_MESSAGE_ROLE_SET: ReadonlySet<string> = new Set(TEST_MESSAGE_ROLE_VALUES);
 40→
 41→/**
 42→ * Text or structured payload attached to a message.
 43→ */
 44→export type TestMessageContent = string | JsonObject | readonly JsonObject[];
 45→
 46→/**
 47→ * System-authored instruction message.
 48→ */
 49→export type SystemTestMessage = {
 50→  readonly role: 'system';
 51→  readonly content: TestMessageContent;
 52→};
 53→
 54→/**
 55→ * User-authored prompt message.
 56→ */
 57→export type UserTestMessage = {
 58→  readonly role: 'user';
 59→  readonly content: TestMessageContent;
 60→};
 61→
 62→/**
 63→ * Assistant response message.
 64→ */
 65→export type AssistantTestMessage = {
 66→  readonly role: 'assistant';
 67→  readonly content: TestMessageContent;
 68→};
 69→
 70→/**
 71→ * Tool invocation message.
 72→ */
 73→export type ToolTestMessage = {
 74→  readonly role: 'tool';
 75→  readonly content: TestMessageContent;
 76→};
 77→
 78→/**
 79→ * Conversation message union with role discrimination.
 80→ */
 81→export type TestMessage =
 82→  | SystemTestMessage
 83→  | UserTestMessage
 84→  | AssistantTestMessage
 85→  | ToolTestMessage;
 86→
 87→/**
 88→ * Guard validating supported message roles.
 89→ */
 90→export function isTestMessageRole(value: unknown): value is TestMessageRole {
 91→  return typeof value === 'string' && TEST_MESSAGE_ROLE_SET.has(value);
 92→}
 93→
 94→/**
 95→ * Guard matching AgentV JSON objects.
 96→ */
 97→export function isJsonObject(value: unknown): value is JsonObject {
 98→  if (typeof value !== 'object' || value === null || Array.isArray(value)) {
 99→    return false;
100→  }
101→  return Object.values(value as Record<string, unknown>).every(isJsonValue);
102→}
103→
104→/**
105→ * Guard matching AgentV JSON values.
106→ */
107→export function isJsonValue(value: unknown): value is JsonValue {
108→  if (
109→    value === null ||
110→    typeof value === 'string' ||
111→    typeof value === 'number' ||
112→    typeof value === 'boolean'
113→  ) {
114→    return true;
115→  }
116→  if (Array.isArray(value)) {
117→    return value.every(isJsonValue);
118→  }
119→  if (typeof value === 'object') {
120→    return isJsonObject(value);
121→  }
122→  return false;
123→}
124→
125→/**
126→ * Guard validating raw test messages.
127→ * A valid test message has:
128→ * - A valid role (system, user, assistant, tool)
129→ * - Either content (string or array of objects) OR tool_calls (for assistant messages)
130→ */
131→export function isTestMessage(value: unknown): value is TestMessage {
132→  if (typeof value !== 'object' || value === null) {
