112→async function findGraderScript(graderName: string, startDir: string): Promise<string | null> {
113→  let dir = path.resolve(startDir);
114→  const root = path.parse(dir).root;
115→
116→  while (dir !== root) {
117→    // Search .agentv/graders/ first, then fall back to .agentv/judges/ for backward compat
118→    for (const subdir of ['graders', 'judges']) {
119→      const gradersDir = path.join(dir, '.agentv', subdir);
120→      const found = await fg([`${graderName}.{ts,js,mts,mjs}`], {
121→        cwd: gradersDir,
122→        absolute: true,
123→        onlyFiles: true,
124→      });
125→      if (found.length > 0) return found[0];
126→    }
127→    dir = path.dirname(dir);
128→  }
129→
130→  return null;
131→}
