 5→import { HtmlWriter } from './html-writer.js';
 6→import { JsonWriter } from './json-writer.js';
 7→import { JsonlWriter } from './jsonl-writer.js';
 8→import { JunitWriter } from './junit-writer.js';
 9→import { YamlWriter } from './yaml-writer.js';
10→
11→export type OutputFormat = 'jsonl' | 'yaml' | 'html';
12→
13→export interface OutputWriter {
14→  append(result: EvaluationResult): Promise<void>;
15→  close(): Promise<void>;
16→}
17→
18→export async function createOutputWriter(
19→  filePath: string,
20→  format: OutputFormat,
21→): Promise<OutputWriter> {
22→  switch (format) {
23→    case 'jsonl':
24→      return JsonlWriter.open(filePath);
25→    case 'yaml':
26→      return YamlWriter.open(filePath);
27→    case 'html':
28→      return HtmlWriter.open(filePath);
29→    default: {
30→      const exhaustiveCheck: never = format;
31→      throw new Error(`Unsupported output format: ${exhaustiveCheck}`);
32→    }
33→  }
34→}
35→
36→const SUPPORTED_EXTENSIONS = new Set(['.jsonl', '.json', '.xml', '.yaml', '.yml', '.html', '.htm']);
37→
38→export function createWriterFromPath(filePath: string): Promise<OutputWriter> {
39→  const ext = path.extname(filePath).toLowerCase();
40→  switch (ext) {
41→    case '.jsonl':
42→      return JsonlWriter.open(filePath);
43→    case '.json':
44→      return JsonWriter.open(filePath);
45→    case '.xml':
46→      return JunitWriter.open(filePath);
47→    case '.yaml':
48→    case '.yml':
49→      return YamlWriter.open(filePath);
50→    case '.html':
51→    case '.htm':
52→      return HtmlWriter.open(filePath);
53→    default:
54→      throw new Error(
55→        `Unsupported output file extension "${ext}". Supported: ${[...SUPPORTED_EXTENSIONS].join(', ')}`,
56→      );
57→  }
58→}
59→
60→export async function createMultiWriter(filePaths: readonly string[]): Promise<OutputWriter> {
61→  const writers = await Promise.all(filePaths.map((fp) => createWriterFromPath(fp)));
62→  return {
63→    async append(result: EvaluationResult): Promise<void> {
64→      await Promise.all(writers.map((w) => w.append(result)));
65→    },
66→    async close(): Promise<void> {
67→      await Promise.all(writers.map((w) => w.close()));
68→    },
69→  };
70→}
