771→  // Load .agentv/config.yaml for execution defaults.
772→  // loadConfig expects an eval file path and walks up from its directory.
773→  // Pass a dummy file in cwd so the search starts from the working directory.
774→  const yamlConfig = await loadConfig(path.join(cwd, '_'), repoRoot);
775→
776→  // Check required_version before proceeding with eval
777→  if (yamlConfig?.required_version) {
778→    await enforceRequiredVersion(yamlConfig.required_version, {
779→      strict: normalizeBoolean(input.rawOptions.strict),
